def validate(args, output):
    nums, k = args[0], args[1]
    if not isinstance(output, list) or len(output) != k:
        return False
    i = 0
    for x in nums:
        if i < len(output) and x == output[i]:
            i += 1
    if i != len(output):
        return False
    target = sum(sorted(nums, reverse=True)[:k])
    return sum(output) == target

