function validate(args, output) {
    const nums = args[0];
    const k = args[1];
    if (!Array.isArray(output) || output.length !== k) return false;
    let i = 0;
    for (const x of nums) {
        if (i < output.length && x === output[i]) i++;
    }
    if (i !== output.length) return false;
    const sorted = nums.slice().sort((a, b) => b - a);
    let target = 0;
    for (let j = 0; j < k; j++) target += sorted[j];
    let total = 0;
    for (const v of output) total += v;
    return total === target;
}

