var maxSubsequence = function(nums, k) {
    const idx = nums.map((_, i) => i);
    idx.sort((a, b) => {
        if (nums[b] !== nums[a]) return nums[b] - nums[a];
        return a - b;
    });
    const chosen = idx.slice(0, k).sort((a, b) => a - b);
    return chosen.map(i => nums[i]);
};
